'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import { ChatMessage } from '@/components/chat-message';
import { ChatInput, type ReasoningEffort } from '@/components/chat-input';
import { ChatLayout } from '@/components/chat-layout';
import { useThread, updateThreadTitle, updateThreadModel, touchThread, updateReasoningEffort } from '@/hooks/use-threads';
import { useMessages, addMessage, deleteMessage } from '@/hooks/use-messages';
import { DEFAULT_MODEL, AVAILABLE_MODELS } from '@/lib/constants';
import { Button } from '@/components/ui/button';
import { Wand2, BookOpen, Code, GraduationCap, Brain, Settings, ChevronUp, ChevronDown, Loader2 } from 'lucide-react';
import { cn } from '@/lib/utils';

interface ChatPageClientProps {
    chatId: string;
}

interface ChatMessageType {
    id: string;
    role: 'user' | 'assistant';
    content: string;
    reasoning?: string;
}

const SUGGESTED_PROMPTS = [
    "How does AI work?",
    "Are black holes real?",
    "How many Rs are in the word \"strawberry\"?",
    "What is the meaning of life?",
];

const CATEGORIES = [
    { icon: Wand2, label: 'Create' },
    { icon: BookOpen, label: 'Explore' },
    { icon: Code, label: 'Code' },
    { icon: GraduationCap, label: 'Learn' },
];

export function ChatPageClient({ chatId }: ChatPageClientProps) {
    const thread = useThread(chatId);
    const storedMessages = useMessages(chatId);
    const scrollRef = useRef<HTMLDivElement>(null);
    const [model, setModel] = useState<string>(DEFAULT_MODEL);
    const [inputValue, setInputValue] = useState('');
    const [messages, setMessages] = useState<ChatMessageType[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isThinking, setIsThinking] = useState(false);
    const [reasoningEffort, setReasoningEffort] = useState<ReasoningEffort>('low');
    const [isAtBottom, setIsAtBottom] = useState(true);
    const hasInitialized = useRef(false);
    const abortControllerRef = useRef<AbortController | null>(null);
    const generatingRef = useRef<string | null>(null);

    useEffect(() => {
        if (thread?.model) {
            setModel(thread.model);
        }
        setReasoningEffort(thread?.reasoningEffort ?? 'low');
    }, [thread]);

    useEffect(() => {
        if (!hasInitialized.current && storedMessages.length > 0) {
            hasInitialized.current = true;
            setMessages(
                storedMessages.map((m) => ({
                    id: m.id,
                    role: m.role,
                    content: m.content,
                    reasoning: m.reasoning,
                }))
            );
        }
    }, [storedMessages]);

    useEffect(() => {
        hasInitialized.current = false;
        setMessages([]);
        setInputValue('');
        setIsLoading(false);
        setIsThinking(false);
        generatingRef.current = null;
        // Reset reasoning effort only if it's not already 'low' or if we want to default to 'low' for new chats
        setReasoningEffort('low');
        setIsAtBottom(true);
    }, [chatId]);

    const scrollToBottom = useCallback(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
            setIsAtBottom(true);
        }
    }, []);

    const handleScroll = useCallback(() => {
        if (scrollRef.current) {
            const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
            const atBottom = scrollHeight - scrollTop - clientHeight < 50;
            setIsAtBottom(atBottom);
        }
    }, []);

    useEffect(() => {
        if (scrollRef.current && isAtBottom) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages, isThinking, isAtBottom]);

    const handleModelChange = async (newModel: string) => {
        setModel(newModel);
        await updateThreadModel(chatId, newModel);
    };

    const handleReasoningEffortChange = async (effort: ReasoningEffort) => {
        setReasoningEffort(effort);
        await updateReasoningEffort(chatId, effort);
    };

    const handleStop = useCallback(() => {
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
            abortControllerRef.current = null;
            setIsLoading(false);
            setIsThinking(false);
            generatingRef.current = null;
        }
    }, []);

    const generateResponse = useCallback(async (currentMessages: ChatMessageType[]) => {
        const lastMsg = currentMessages[currentMessages.length - 1];
        if (generatingRef.current === lastMsg.id) return;
        generatingRef.current = lastMsg.id;

        setIsThinking(true);
        setIsLoading(true);
        abortControllerRef.current = new AbortController();

        // Update title if it's a new chat and we have at least one message
        const selectedModel = AVAILABLE_MODELS.find(m => m.id === model);
        const supportsReasoning = selectedModel?.supportsReasoning ?? true;

        if (thread?.title === 'New Chat' && currentMessages.length > 0) {
            const firstUserMsg = currentMessages.find(m => m.role === 'user');
            if (firstUserMsg) {
                const title = firstUserMsg.content.slice(0, 50) + (firstUserMsg.content.length > 50 ? '...' : '');
                updateThreadTitle(chatId, title);
            }
        }

        try {
            const response = await fetch('/api/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    messages: currentMessages.map((m) => ({ role: m.role, content: m.content })),
                    model,
                    reasoningEffort,
                }),
                signal: abortControllerRef.current.signal,
            });

            if (!response.ok) {
                throw new Error('Failed to get response');
            }

            const assistantMsgId = crypto.randomUUID();
            const assistantMsg: ChatMessageType = {
                id: assistantMsgId,
                role: 'assistant',
                content: '',
                reasoning: '',
            };
            setMessages(prev => [...prev, assistantMsg]);

            const reader = response.body?.getReader();
            const decoder = new TextDecoder();
            let fullContent = '';
            let fullReasoning = '';

            if (reader) {
                let buffer = '';
                while (true) {
                    const { done, value } = await reader.read();
                    if (done) break;

                    buffer += decoder.decode(value, { stream: true });
                    const lines = buffer.split('\n');
                    buffer = lines.pop() || '';

                    for (const line of lines) {
                        if (line.startsWith('data: ')) {
                            const data = line.slice(6);
                            if (data === '[DONE]') continue;

                            try {
                                const parsed = JSON.parse(data);
                                const delta = parsed.choices?.[0]?.delta;

                                // Check for reasoning content (some models use reasoning_content)
                                const reasoningContent = delta?.reasoning_content || delta?.thinking || '';
                                if (reasoningContent && supportsReasoning) {
                                    fullReasoning += reasoningContent;
                                    setMessages((prev) => {
                                        const updated = [...prev];
                                        const msgIdx = updated.findIndex(m => m.id === assistantMsgId);
                                        if (msgIdx !== -1) {
                                            updated[msgIdx] = {
                                                ...updated[msgIdx],
                                                reasoning: fullReasoning,
                                            };
                                        }
                                        return updated;
                                    });
                                    // Still thinking while we have reasoning content
                                    setIsThinking(true);
                                }

                                // Check for main content
                                const content = delta?.content || '';
                                if (content) {
                                    // Once we get main content, thinking is done
                                    setIsThinking(false);
                                    fullContent += content;
                                    setMessages((prev) => {
                                        const updated = [...prev];
                                        const msgIdx = updated.findIndex(m => m.id === assistantMsgId);
                                        if (msgIdx !== -1) {
                                            updated[msgIdx] = {
                                                ...updated[msgIdx],
                                                content: fullContent,
                                                reasoning: fullReasoning,
                                            };
                                        }
                                        return updated;
                                    });
                                }
                            } catch {
                                // Skip malformed JSON
                            }
                        }
                    }
                }
            }

            await addMessage(chatId, 'assistant', fullContent, fullReasoning);
            await touchThread(chatId);
        } catch (error) {
            if (error instanceof Error && error.name === 'AbortError') {
                // User stopped
            } else {
                console.error('Chat error:', error);
                // Remove the empty assistant message if it failed
                setMessages(currentMessages);
            }
        } finally {
            setIsLoading(false);
            setIsThinking(false);
            generatingRef.current = null;
            abortControllerRef.current = null;
        }
    }, [chatId, model, reasoningEffort, thread]);

    // Check for pending user message on load (e.g. new chat from home)
    useEffect(() => {
        if (hasInitialized.current && messages.length > 0 && !isLoading && !isThinking) {
            const lastMessage = messages[messages.length - 1];
            if (lastMessage.role === 'user') {
                generateResponse(messages);
            }
        }
    }, [messages, isLoading, isThinking, generateResponse]);

    const sendMessage = useCallback(async (userMessage: string, existingMessages: ChatMessageType[]) => {
        const userMsg: ChatMessageType = {
            id: crypto.randomUUID(),
            role: 'user',
            content: userMessage,
        };

        const updatedMessages = [...existingMessages, userMsg];
        setMessages(updatedMessages);
        await addMessage(chatId, 'user', userMessage);

        await generateResponse(updatedMessages);
    }, [chatId, generateResponse]);

    const handleSend = useCallback(async () => {
        if (!inputValue.trim() || isLoading) return;
        const userMessage = inputValue.trim();
        setInputValue('');
        setIsAtBottom(true);
        await sendMessage(userMessage, messages);
    }, [inputValue, isLoading, messages, sendMessage]);

    const handlePromptClick = (prompt: string) => {
        setInputValue(prompt);
    };

    const handleEdit = useCallback(async (messageId: string, newContent: string) => {
        const msgIndex = messages.findIndex(m => m.id === messageId);
        if (msgIndex === -1) return;

        const previousMessages = messages.slice(0, msgIndex);
        const messagesToDelete = storedMessages.slice(msgIndex);
        for (const msg of messagesToDelete) {
            await deleteMessage(msg.id);
        }

        const userMsg: ChatMessageType = {
            id: crypto.randomUUID(),
            role: 'user',
            content: newContent
        };
        const updatedMessages = [...previousMessages, userMsg];

        setMessages(updatedMessages);
        await addMessage(chatId, 'user', newContent);

        await generateResponse(updatedMessages);
    }, [messages, storedMessages, chatId, generateResponse]);

    const handleRetry = useCallback(async (messageId: string) => {
        let msgIndex = messages.findIndex(m => m.id === messageId);
        if (msgIndex === -1) return;

        // If retrying an assistant message, find the preceding user message
        if (messages[msgIndex].role === 'assistant') {
            msgIndex = messages.slice(0, msgIndex).findLastIndex(m => m.role === 'user');
            if (msgIndex === -1) return;
        } else if (messages[msgIndex].role !== 'user') {
            return;
        }

        const previousMessages = messages.slice(0, msgIndex + 1); // Include the user message
        const messagesToDelete = storedMessages.slice(msgIndex + 1); // Delete responses after it

        for (const msg of messagesToDelete) {
            await deleteMessage(msg.id);
        }

        setMessages(previousMessages);
        await generateResponse(previousMessages);
    }, [messages, storedMessages, generateResponse]);

    const handleDelete = useCallback(async (messageId: string) => {
        await deleteMessage(messageId);
        setMessages(prev => prev.filter(m => m.id !== messageId));
    }, []);

    return (
        <ChatLayout>
            <div className="flex flex-col h-full bg-[#1a1520]">
                {/* Settings button in top right */}
                <div className="absolute top-6 right-8 z-10">
                    <Button
                        variant="ghost"
                        size="icon"
                        className="h-9 w-9 text-zinc-500 hover:text-zinc-300 hover:bg-[#2a2035]/50 rounded-xl transition-all"
                    >
                        <Settings className="h-5 w-5" />
                    </Button>
                </div>

                <div
                    ref={scrollRef}
                    className="flex-1 overflow-y-auto scroll-smooth"
                    onScroll={handleScroll}
                >
                    {messages.length === 0 && !isThinking ? (
                        <div className="flex flex-col items-center justify-center h-full px-4">
                            {/* Main heading */}
                            <h1 className="text-3xl font-bold text-zinc-100 mb-6">
                                How can I help you?
                            </h1>

                            {/* Category buttons */}
                            <div className="flex gap-2 mb-8">
                                {CATEGORIES.map((cat) => (
                                    <Button
                                        key={cat.label}
                                        variant="ghost"
                                        className="h-9 px-4 gap-2 text-zinc-400 bg-transparent hover:bg-[#2a2035] border border-[#3a3045] rounded-full text-sm"
                                    >
                                        <cat.icon className="h-4 w-4" />
                                        {cat.label}
                                    </Button>
                                ))}
                            </div>

                            {/* Suggested prompts */}
                            <div className="space-y-1 w-full max-w-md text-left">
                                {SUGGESTED_PROMPTS.map((prompt, i) => (
                                    <button
                                        key={i}
                                        onClick={() => handlePromptClick(prompt)}
                                        className="w-full text-left px-1 py-2 text-sm text-pink-300/80 hover:text-pink-200 transition-colors"
                                    >
                                        {prompt}
                                    </button>
                                ))}
                            </div>

                            {/* Terms and Privacy Policy (at bottom) */}
                            <div className="absolute bottom-24 left-0 right-0 text-center">
                                <p className="text-xs text-zinc-500">
                                    Make sure you agree to our{' '}
                                    <span className="underline cursor-pointer hover:text-zinc-400">Terms</span>
                                    {' '}and our{' '}
                                    <span className="underline cursor-pointer hover:text-zinc-400">Privacy Policy</span>
                                </p>
                            </div>
                        </div>
                    ) : (
                        <div className="max-w-3xl mx-auto pt-8 pb-4">
                            {messages.map((message, i) => {
                                const selectedModel = AVAILABLE_MODELS.find((m) => m.id === model);
                                return (
                                    <ChatMessage
                                        key={message.id}
                                        id={message.id}
                                        role={message.role}
                                        content={message.content.replace(/^(#{1,6})([^#\s])/gm, '$1 $2')}
                                        reasoning={message.reasoning}
                                        isStreaming={isLoading && i === messages.length - 1 && message.role === 'assistant'}
                                        isThinking={isThinking && i === messages.length - 1 && message.role === 'assistant'}
                                        modelName={message.role === 'assistant' ? selectedModel?.name : undefined}
                                        onEdit={message.role === 'user' ? handleEdit : undefined}
                                        onRetry={handleRetry}
                                        onDelete={handleDelete}
                                    />
                                );
                            })}
                        </div>
                    )}
                </div>

                <div className="relative w-full max-w-3xl mx-auto px-4">
                    {/* Floating Scroll to Bottom Button - Pill Style */}
                    {!isAtBottom && scrollRef.current && scrollRef.current.scrollHeight > scrollRef.current.clientHeight && (
                        <div className="absolute -top-14 left-1/2 -translate-x-1/2 animate-in fade-in slide-in-from-bottom-2 duration-300">
                            <button
                                onClick={scrollToBottom}
                                className="h-9 px-4 rounded-full bg-zinc-900/60 backdrop-blur-lg border border-white/5 text-zinc-300 hover:text-zinc-100 hover:bg-zinc-800/80 shadow-2xl transition-all flex items-center gap-2 group"
                            >
                                <span className="text-xs font-semibold tracking-tight">Scroll to bottom</span>
                                <ChevronDown className="h-4 w-4 transition-transform group-hover:translate-y-0.5" />
                            </button>
                        </div>
                    )}
                </div>

                <ChatInput
                    value={inputValue}
                    onChange={setInputValue}
                    onSubmit={handleSend}
                    onStop={handleStop}
                    isLoading={isLoading}
                    currentModel={model}
                    onModelChange={handleModelChange}
                    reasoningEffort={reasoningEffort}
                    onReasoningEffortChange={handleReasoningEffortChange}
                />
            </div>
        </ChatLayout>
    );
}

'use client';

import { useRef, useEffect, useState } from 'react';
import { Button } from '@/components/ui/button';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { ArrowUp, Square, ChevronUp, ChevronDown, Paperclip, Check, Sparkles, Search, Globe, Brain } from 'lucide-react';
import { AVAILABLE_MODELS } from '@/lib/constants';
import { cn } from '@/lib/utils';

export type ReasoningEffort = 'low' | 'medium' | 'high';

interface ChatInputProps {
    value: string;
    onChange: (value: string) => void;
    onSubmit: () => void;
    onStop: () => void;
    isLoading: boolean;
    currentModel: string;
    onModelChange: (model: string) => void;
    reasoningEffort: ReasoningEffort;
    onReasoningEffortChange: (effort: ReasoningEffort) => void;
}

const REASONING_OPTIONS: { value: ReasoningEffort; label: string; pro?: boolean }[] = [
    { value: 'low', label: 'Low' },
    { value: 'medium', label: 'Medium' },
    { value: 'high', label: 'High' },
];

export function ChatInput({
    value,
    onChange,
    onSubmit,
    onStop,
    isLoading,
    currentModel,
    onModelChange,
    reasoningEffort,
    onReasoningEffortChange,
}: ChatInputProps) {
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const selectedModel = AVAILABLE_MODELS.find((m) => m.id === currentModel) ?? AVAILABLE_MODELS[0];
    const selectedReasoning = REASONING_OPTIONS.find(r => r.value === reasoningEffort) ?? REASONING_OPTIONS[0];

    useEffect(() => {
        if (textareaRef.current) {
            textareaRef.current.style.height = 'auto';
            textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 200) + 'px';
        }
    }, [value]);

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            if (!isLoading && value?.trim()) {
                onSubmit();
            }
        }
    };

    return (
        <div className="pb-4 px-4 pt-0 bg-[#1a1520]">
            <div className="max-w-3xl mx-auto">
                {/* Input Container */}
                <div className="relative rounded-2xl bg-[#221c26] border border-[#302736]/60 shadow-xl transition-all duration-200">
                    {/* Textarea */}
                    <textarea
                        ref={textareaRef}
                        value={value}
                        onChange={(e) => onChange(e.target.value)}
                        onKeyDown={handleKeyDown}
                        placeholder="Type your message here..."
                        disabled={isLoading}
                        rows={1}
                        className="w-full px-5 pt-4 pb-14 bg-transparent text-zinc-100 placeholder:text-zinc-500/80 focus:outline-none resize-none disabled:opacity-50 min-h-[60px] text-[15px] leading-relaxed"
                    />

                    {/* Bottom Bar */}
                    <div className="absolute bottom-0 left-0 right-0 flex items-center justify-between px-4 pb-3">
                        {/* Left side - Model selector and tools */}
                        <div className="flex items-center gap-3">
                            {/* Model Selector - Plain text style */}
                            <DropdownMenu>
                                <DropdownMenuTrigger asChild>
                                    <Button
                                        variant="ghost"
                                        className="h-8 pl-0 pr-2 gap-2 text-zinc-100 hover:text-white hover:bg-transparent p-0 text-sm font-bold tracking-tight"
                                    >
                                        <span className="">{selectedModel.name}</span>
                                        <ChevronDown className="h-3 w-3 opacity-50" />
                                    </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent
                                    align="start"
                                    side="top"
                                    className="w-80 bg-[#1a1520] border-[#3a3045] shadow-2xl mb-2 max-h-[400px] overflow-y-auto"
                                >
                                    {/* Search */}
                                    <div className="p-2 border-b border-[#2a2535]">
                                        <div className="flex items-center gap-2 px-2 py-1.5 rounded-lg bg-[#252030]">
                                            <Search className="h-4 w-4 text-zinc-500" />
                                            <input
                                                type="text"
                                                placeholder="Search models..."
                                                className="flex-1 bg-transparent text-sm text-zinc-300 placeholder:text-zinc-600 focus:outline-none"
                                            />
                                        </div>
                                    </div>

                                    {/* Model List */}
                                    <div className="py-1">
                                        {AVAILABLE_MODELS.map((model) => (
                                            <DropdownMenuItem
                                                key={model.id}
                                                onClick={() => onModelChange(model.id)}
                                                className={cn(
                                                    'flex items-start gap-3 py-3 px-3 cursor-pointer focus:bg-[#2a2535]',
                                                    model.id === currentModel && 'bg-[#2a2535]'
                                                )}
                                            >
                                                <Sparkles className="h-4 w-4 text-emerald-400 mt-0.5 shrink-0" />
                                                <div className="flex-1 min-w-0">
                                                    <div className="flex items-center gap-2">
                                                        <span className="font-medium text-zinc-100">{model.name}</span>
                                                        {model.id === currentModel && (
                                                            <Check className="h-3.5 w-3.5 text-emerald-400" />
                                                        )}
                                                    </div>
                                                    <span className="text-xs text-zinc-500 block">{model.description}</span>
                                                </div>
                                            </DropdownMenuItem>
                                        ))}
                                    </div>
                                </DropdownMenuContent>
                            </DropdownMenu>

                            {/* Reasoning Effort Selector - Pill style */}
                            {selectedModel.supportsReasoning && (
                                <div className="group/reasoning relative flex flex-col items-center">
                                    <DropdownMenu>
                                        <DropdownMenuTrigger asChild>
                                            <Button
                                                variant="ghost"
                                                className="h-8 px-3 gap-2 text-[#fce7ef] hover:text-white bg-[#2a2035]/30 hover:bg-[#2a2035]/50 border border-white/10 rounded-full transition-all text-xs font-semibold"
                                            >
                                                <Brain className="h-4 w-4" />
                                                <span className="capitalize">{selectedReasoning.label}</span>
                                            </Button>
                                        </DropdownMenuTrigger>
                                        <DropdownMenuContent
                                            align="start"
                                            side="top"
                                            className="w-44 bg-[#1a1520] border-[#3a3045] shadow-2xl mb-2"
                                        >
                                            {REASONING_OPTIONS.map((option) => (
                                                <DropdownMenuItem
                                                    key={option.value}
                                                    onClick={() => onReasoningEffortChange(option.value)}
                                                    className={cn(
                                                        'flex items-center gap-2 py-2.5 px-3 cursor-pointer focus:bg-[#2a2535]',
                                                        option.value === reasoningEffort && 'bg-[#2a2535]'
                                                    )}
                                                >
                                                    <Brain className="h-4 w-4 text-zinc-400" />
                                                    <span className="text-zinc-100">{option.label}</span>
                                                    {option.pro && (
                                                        <span className="text-[10px] text-zinc-500 ml-auto">Pro</span>
                                                    )}
                                                    {option.value === reasoningEffort && (
                                                        <Check className="h-3.5 w-3.5 text-emerald-400 ml-auto" />
                                                    )}
                                                </DropdownMenuItem>
                                            ))}
                                        </DropdownMenuContent>
                                    </DropdownMenu>

                                    {/* Custom Tooltip */}
                                    <div className="absolute bottom-full mb-2 hidden group-hover/reasoning:block z-50 pointer-events-none">
                                        <div className="bg-[#1a1520]/95 backdrop-blur-md text-[11px] px-2.5 py-1.5 rounded-lg whitespace-nowrap shadow-2xl border border-white/10 font-semibold tracking-tight animate-in fade-in zoom-in-95 duration-200">
                                            <span className="text-[#fce7ef]">Reasoning Effort</span>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {/* Search Button - Pill style */}
                            <Button
                                variant="ghost"
                                className="h-8 px-3 gap-2 text-[#fce7ef] hover:text-white bg-[#2a2035]/30 hover:bg-[#2a2035]/50 border border-white/10 rounded-full transition-all text-xs font-semibold"
                            >
                                <Globe className="h-4 w-4" />
                                <span className="">Search</span>
                            </Button>

                            {/* Attachment - Pill style */}
                            <Button
                                variant="ghost"
                                className="h-8 w-11 p-0 text-[#fce7ef] hover:text-white bg-[#2a2035]/30 hover:bg-[#2a2035]/50 border border-white/10 rounded-full transition-all flex items-center justify-center"
                                title="Attach file"
                            >
                                <Paperclip className="h-4 w-4" />
                            </Button>
                        </div>

                        {/* Right side - Send/Stop button */}
                        {isLoading ? (
                            <Button
                                type="button"
                                size="icon"
                                onClick={onStop}
                                className="h-8 w-8 rounded-lg bg-red-500/10 hover:bg-red-500/20 text-red-400 transition-all border border-red-500/20"
                            >
                                <Square className="h-3.5 w-3.5 fill-current" />
                            </Button>
                        ) : (
                            <Button
                                type="button"
                                size="icon"
                                onClick={onSubmit}
                                disabled={!value?.trim()}
                                className="h-8 w-8 rounded-lg bg-[#3a283e] hover:bg-[#4a354e] text-pink-300/80 transition-all shadow-lg disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <ArrowUp className="h-4 w-4" />
                            </Button>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import ReactMarkdown from 'react-markdown';
import rehypeHighlight from 'rehype-highlight';
import rehypeRaw from 'rehype-raw';
import remarkGfm from 'remark-gfm';
import { Copy, RefreshCcw, SquarePen, GitBranch, ChevronDown, ChevronUp, Brain, Loader2 } from 'lucide-react';
import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';

interface ChatMessageProps {
    id: string;
    role: 'user' | 'assistant';
    content: string;
    isStreaming?: boolean;
    isThinking?: boolean;
    modelName?: string;
    reasoning?: string;
    onEdit?: (id: string, newContent: string) => void;
    onRetry?: (id: string) => void;
    onDelete?: (id: string) => void;
}

export function ChatMessage({
    id,
    role,
    content,
    isStreaming,
    isThinking,
    modelName,
    reasoning,
    onEdit,
    onRetry,
    onDelete,
}: ChatMessageProps) {
    const [copied, setCopied] = useState(false);
    const [isEditing, setIsEditing] = useState(false);
    const [editContent, setEditContent] = useState(content);
    // Collapsed by default
    const [reasoningExpanded, setReasoningExpanded] = useState(false);
    const isUser = role === 'user';

    const handleCopy = async () => {
        await navigator.clipboard.writeText(content);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    const handleEdit = () => {
        setEditContent(content);
        setIsEditing(true);
    };

    const handleSaveEdit = () => {
        if (onEdit && editContent.trim()) {
            onEdit(id, editContent.trim());
        }
        setIsEditing(false);
    };

    const handleCancelEdit = () => {
        setEditContent(content);
        setIsEditing(false);
    };

    const ActionIcon = ({
        icon: Icon,
        title,
        onClick,
        className
    }: {
        icon: any;
        title: string;
        onClick?: () => void;
        className?: string;
    }) => (
        <div className="relative group/icon flex flex-col items-center">
            <button
                onClick={onClick}
                className={cn(
                    "p-2 rounded-lg text-zinc-400/70 hover:text-zinc-100 hover:bg-zinc-800/50 transition-all",
                    className
                )}
            >
                <Icon className="h-[1.1rem] w-[1.1rem]" />
            </button>
            <div className="absolute top-full mt-2 hidden group-hover/icon:block z-20 pointer-events-none">
                <div className="bg-zinc-950 text-white text-[11px] px-2.5 py-1.5 rounded-lg whitespace-nowrap shadow-2xl border border-white/5 font-medium tracking-tight animate-in fade-in zoom-in-95 duration-200">
                    {title}
                </div>
            </div>
        </div>
    );

    // User message - right aligned with bubble
    if (isUser) {
        return (
            <div className="flex flex-col items-end py-6 px-4 group mb-6">
                {isEditing ? (
                    <div className="w-full max-w-[75%] flex flex-col gap-2">
                        <textarea
                            value={editContent}
                            onChange={(e) => setEditContent(e.target.value)}
                            className="w-full min-h-[80px] p-3 bg-[#2a2035] text-zinc-100 rounded-2xl border border-[#3a2a4a] focus:border-pink-500/50 focus:outline-none resize-none"
                            autoFocus
                        />
                        <div className="flex gap-2 justify-end">
                            <Button
                                size="sm"
                                variant="ghost"
                                onClick={handleCancelEdit}
                                className="text-zinc-400 hover:text-zinc-200"
                            >
                                Cancel
                            </Button>
                            <Button
                                size="sm"
                                onClick={handleSaveEdit}
                                className="bg-pink-600 hover:bg-pink-500 text-white"
                            >
                                Save & Resend
                            </Button>
                        </div>
                    </div>
                ) : (
                    <>
                        <div className="max-w-[75%] rounded-2xl px-4 py-3 bg-[#2a2035]/80 backdrop-blur-sm border border-white/5 text-zinc-100 shadow-lg">
                            <p className="whitespace-pre-wrap break-words text-[15px] leading-relaxed">{content}</p>
                        </div>
                        {/* Action icons below message - same row */}
                        <div className="flex items-center gap-1 mt-1 opacity-0 group-hover:opacity-100 transition-opacity translate-x-1">
                            {onRetry && (
                                <ActionIcon
                                    icon={RefreshCcw}
                                    title="Regenerate"
                                    onClick={() => onRetry(id)}
                                />
                            )}
                            <ActionIcon
                                icon={GitBranch}
                                title="Branch"
                            />
                            {onEdit && (
                                <ActionIcon
                                    icon={SquarePen}
                                    title="Edit message"
                                    onClick={handleEdit}
                                />
                            )}
                            <ActionIcon
                                icon={Copy}
                                title="Copy message"
                                onClick={handleCopy}
                            />
                        </div>
                    </>
                )}
            </div>
        );
    }

    // Assistant message - left aligned, plain text, no bubble
    if (!isUser && !content && !reasoning && !isThinking) return null;

    return (
        <div className="py-6 px-4 group">
            <div className="max-w-3xl">
                {/* Reasoning section (collapsible) */}
                {(reasoning || isThinking) && (
                    <div className="mb-6">
                        <div
                            className={cn(
                                "rounded-xl transition-all duration-300 ease-in-out overflow-hidden border",
                                reasoningExpanded
                                    ? "bg-[#16121a] border-white/5 shadow-xl"
                                    : "bg-transparent border-transparent"
                            )}
                        >
                            <button
                                onClick={() => setReasoningExpanded(!reasoningExpanded)}
                                className={cn(
                                    "flex items-center gap-1.5 transition-colors px-0 py-2",
                                    reasoningExpanded ? "border-b border-white/5 bg-white/[0.02] -mx-3 px-3 w-[calc(100%+1.5rem)]" : ""
                                )}
                            >
                                <Brain className={cn(
                                    "h-4 w-4 shrink-0 transition-colors",
                                    reasoningExpanded ? "text-pink-400/80" : "text-zinc-500"
                                )} />
                                <span className="text-[13px] font-medium tracking-tight text-zinc-400">Reasoning</span>
                                <ChevronDown className={cn(
                                    "h-3.5 w-3.5 text-zinc-600/80 shrink-0 transition-transform duration-300",
                                    reasoningExpanded && "rotate-180"
                                )} />
                                {isThinking && <Loader2 className="h-3.5 w-3.5 animate-spin text-zinc-600/50 shrink-0 ml-1" />}
                            </button>

                            <div
                                className={cn(
                                    "grid transition-all duration-300 ease-in-out",
                                    reasoningExpanded ? "grid-rows-[1fr] opacity-100" : "grid-rows-[0fr] opacity-0"
                                )}
                            >
                                <div className="overflow-hidden">
                                    <div className="p-4 pt-1">
                                        {reasoning ? (
                                            <div className="prose prose-invert prose-sm max-w-none prose-p:text-zinc-400 prose-p:leading-relaxed prose-headings:text-zinc-200 prose-headings:font-semibold prose-strong:text-zinc-200 prose-p:my-3">
                                                <ReactMarkdown
                                                    rehypePlugins={[rehypeHighlight, rehypeRaw]}
                                                    remarkPlugins={[remarkGfm]}
                                                >
                                                    {reasoning}
                                                </ReactMarkdown>
                                            </div>
                                        ) : (
                                            <div className="flex items-center gap-1.5 h-6 opacity-40 py-4">
                                                <span className="w-1.5 h-1.5 rounded-full bg-zinc-500 animate-bounce [animation-delay:-0.3s]" />
                                                <span className="w-1.5 h-1.5 rounded-full bg-zinc-500 animate-bounce [animation-delay:-0.15s]" />
                                                <span className="w-1.5 h-1.5 rounded-full bg-zinc-500 animate-bounce" />
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Main content */}
                {content && (
                    <div className="prose prose-invert max-w-none prose-p:text-zinc-200 prose-p:leading-relaxed prose-p:text-[15px] prose-headings:text-zinc-100 prose-headings:font-semibold prose-strong:text-zinc-100 prose-code:text-pink-300 prose-p:my-4">
                        <ReactMarkdown
                            rehypePlugins={[rehypeHighlight, rehypeRaw]}
                            remarkPlugins={[remarkGfm]}
                            components={{
                                pre: ({ children }) => (
                                    <pre className="bg-[#1a1520]/80 backdrop-blur-sm rounded-xl p-5 overflow-x-auto my-6 border border-[#2d2235]/60 scrollbar-thin scrollbar-thumb-zinc-700 scrollbar-track-transparent">
                                        {children}
                                    </pre>
                                ),
                                code: ({ className, children, ...props }) => {
                                    const isInline = !className;
                                    return isInline ? (
                                        <code className="bg-[#2a2035]/60 px-1.5 py-0.5 rounded-md text-sm text-pink-300 font-mono border border-white/5" {...props}>
                                            {children}
                                        </code>
                                    ) : (
                                        <code className={cn(className, "font-mono text-sm leading-relaxed")} {...props}>
                                            {children}
                                        </code>
                                    );
                                },
                                li: ({ children }) => (
                                    <li className="text-zinc-200/90 py-1">{children}</li>
                                ),
                            }}
                        >
                            {content}
                        </ReactMarkdown>
                    </div>
                )}


                {/* Action icons below AI message */}
                {!isStreaming && content && (
                    <div className="flex items-center gap-1 mt-2 opacity-0 group-hover:opacity-100 transition-opacity -ml-2">
                        {onRetry && (
                            <ActionIcon
                                icon={RefreshCcw}
                                title="Regenerate"
                                onClick={() => onRetry(id)}
                            />
                        )}
                        <ActionIcon
                            icon={GitBranch}
                            title="Branch"
                        />
                        <ActionIcon
                            icon={Copy}
                            title="Copy message"
                            onClick={handleCopy}
                        />
                        {modelName && (
                            <span className="text-xs text-zinc-500/80 font-medium ml-3">{modelName}</span>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
    Plus,
    PanelLeftClose,
    PanelLeft,
    Search,
    Pin,
    X,
} from 'lucide-react';
import { useThreads, deleteThread, toggleThreadPin } from '@/hooks/use-threads';
import { groupThreadsByDate } from '@/lib/date-utils';
import { cn } from '@/lib/utils';

export function Sidebar() {
    const [isCollapsed, setIsCollapsed] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const threads = useThreads();
    const pinnedThreads = threads.filter(t => t.isPinned);
    const unpinnedThreads = threads.filter(t => !t.isPinned);
    const groupedThreads = groupThreadsByDate(unpinnedThreads);
    const pathname = usePathname();
    const router = useRouter();

    const filteredPinned = pinnedThreads.filter(t =>
        t.title.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const filteredGroups = groupedThreads.map(group => ({
        ...group,
        threads: group.threads.filter(t =>
            t.title.toLowerCase().includes(searchQuery.toLowerCase())
        )
    })).filter(g => g.threads.length > 0);

    const handleNewChat = () => {
        router.push('/');
    };

    const handleDelete = async (e: React.MouseEvent, threadId: string) => {
        e.preventDefault();
        e.stopPropagation();
        await deleteThread(threadId);
        if (pathname === `/c/${threadId}`) {
            router.push('/');
        }
    };

    const handleTogglePin = async (e: React.MouseEvent, threadId: string, isPinned: boolean) => {
        e.preventDefault();
        e.stopPropagation();
        await toggleThreadPin(threadId, !isPinned);
    };

    if (isCollapsed) {
        return (
            <div className="fixed top-3 left-3 z-[100] flex items-center gap-0.5 bg-[#0f0a12]/80 backdrop-blur-md p-1.5 rounded-xl border border-[#2a1f2f] shadow-2xl">
                <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setIsCollapsed(false)}
                    className="h-9 w-9 text-zinc-400 hover:text-zinc-100 hover:bg-[#2a1f2f] transition-all rounded-lg"
                >
                    <PanelLeft className="h-5 w-5" />
                </Button>

                <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setIsCollapsed(false)}
                    className="h-9 w-9 text-zinc-400 hover:text-zinc-100 hover:bg-[#2a1f2f] transition-all rounded-lg"
                >
                    <Search className="h-4.5 w-4.5" />
                </Button>

                <Button
                    variant="ghost"
                    size="icon"
                    onClick={handleNewChat}
                    className="h-9 w-9 text-zinc-400 hover:text-zinc-100 hover:bg-[#2a1f2f] transition-all rounded-lg"
                >
                    <Plus className="h-5 w-5" />
                </Button>
            </div>
        );
    }

    const renderThreadItem = (thread: any) => {
        const isActive = pathname === `/c/${thread.id}`;
        return (
            <div
                key={thread.id}
                className="group relative"
            >
                <Link
                    href={`/c/${thread.id}`}
                    className={cn(
                        'flex items-center gap-2 px-3 py-2 text-[13px] transition-all rounded-lg outline-none min-w-0 relative',
                        isActive
                            ? 'bg-[#2a1f2f] text-zinc-100 font-medium'
                            : 'text-zinc-400 hover:bg-[#1f1623] hover:text-zinc-200'
                    )}
                >
                    <span className="truncate flex-1 min-w-0">{thread.title}</span>
                </Link>

                {/* Hover Actions */}
                <div
                    className={cn(
                        "absolute right-1 top-1/2 -translate-y-1/2 flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity pl-2",
                        isActive ? "bg-[#2a1f2f]" : "bg-[#1f1623]",
                        // Add a gradient mask to the left to fade out text
                        "before:absolute before:-left-4 before:top-0 before:bottom-0 before:w-4 text-zinc-500",
                        isActive
                            ? "before:bg-gradient-to-l before:from-[#2a1f2f] before:to-transparent"
                            : "before:bg-gradient-to-l before:from-[#1f1623] before:to-transparent"
                    )}
                >
                    {/* Pin Button */}
                    <div className="relative group/tooltip">
                        <Button
                            variant="ghost"
                            size="icon"
                            className={cn(
                                "h-7 w-7 transition-colors rounded-md",
                                thread.isPinned ? "text-pink-500 hover:bg-pink-500/10" : "text-zinc-500 hover:text-zinc-200 hover:bg-zinc-800/50"
                            )}
                            onClick={(e) => handleTogglePin(e, thread.id, !!thread.isPinned)}
                        >
                            <Pin className={cn("h-3.5 w-3.5 transform rotate-45", thread.isPinned && "fill-current")} />
                        </Button>
                        <div className="absolute bottom-full right-0 mb-2 px-2 py-1 bg-black text-[10px] text-white rounded whitespace-nowrap opacity-0 pointer-events-none group-hover/tooltip:opacity-100 transition-opacity z-50">
                            {thread.isPinned ? 'Unpin Thread' : 'Pin Thread'}
                        </div>
                    </div>

                    {/* Delete Button */}
                    <div className="relative group/tooltip">
                        <Button
                            variant="ghost"
                            size="icon"
                            className="h-7 w-7 text-zinc-500 hover:text-red-400 hover:bg-red-900/20 rounded-md"
                            onClick={(e) => handleDelete(e, thread.id)}
                        >
                            <X className="h-3.5 w-3.5" />
                        </Button>
                        <div className="absolute bottom-full right-0 mb-2 px-2 py-1 bg-black text-[10px] text-white rounded whitespace-nowrap opacity-0 pointer-events-none group-hover/tooltip:opacity-100 transition-opacity z-50">
                            Delete Thread
                        </div>
                    </div>
                </div>
            </div>
        );
    };

    return (
        <aside className="h-screen w-[260px] flex flex-col bg-[#0f0a12] border-r border-[#2a1f2f] overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between p-4 pb-2">
                <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setIsCollapsed(true)}
                    className="h-9 w-9 text-zinc-400 hover:text-zinc-100 hover:bg-[#2a1f2f]"
                >
                    <PanelLeftClose className="h-5 w-5" />
                </Button>
                <span className="font-bold text-zinc-100 text-2xl">dev.chat</span>
                <div className="w-9" />
            </div>

            {/* New Chat Button */}
            <div className="px-3 pb-2 pt-2">
                <Button
                    onClick={handleNewChat}
                    className="w-full h-9 bg-gradient-to-r from-pink-700/90 to-pink-600/90 hover:from-pink-600/90 hover:to-pink-500/90 text-pink-100 font-medium rounded-lg border border-pink-500/20 shadow-pink-500/10 shadow-sm text-[13px] transition-all"
                >
                    New Chat
                </Button>
            </div>

            {/* Search */}
            <div className="px-3 pb-4">
                <div className="flex items-center gap-2 px-3 py-2 text-zinc-500 group">
                    <Search className="h-4 w-4 group-focus-within:text-zinc-300 transition-colors" />
                    <input
                        type="text"
                        placeholder="Search your threads..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="flex-1 bg-transparent text-sm text-zinc-300 placeholder:text-zinc-600 focus:outline-none"
                    />
                </div>
            </div>

            {/* Chat List */}
            <ScrollArea className="flex-1">
                <div className="p-2 pt-0">
                    {/* Pinned Section */}
                    {filteredPinned.length > 0 && (
                        <div className="mb-4">
                            <h3 className="text-xs font-semibold text-pink-500/90 px-4 py-2 mb-1">
                                Pinned
                            </h3>
                            <div className="space-y-0.5 px-2">
                                {filteredPinned.map(renderThreadItem)}
                            </div>
                        </div>
                    )}

                    {/* Grouped Threads */}
                    {filteredGroups.length === 0 && filteredPinned.length === 0 ? (
                        <div className="text-center py-12">
                            <p className="text-sm text-zinc-600">
                                {searchQuery ? 'No results found' : 'No conversations yet'}
                            </p>
                        </div>
                    ) : (
                        filteredGroups.map((group) => (
                            <div key={group.label} className="mb-6">
                                <h3 className="text-xs font-semibold text-pink-500/90 px-4 py-2 mb-1">
                                    {group.label}
                                </h3>
                                <div className="space-y-0.5 px-2">
                                    {group.threads.map(renderThreadItem)}
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </ScrollArea>
        </aside>
    );
}
